module SR_flip_flop (
    input wire S,
    input wire R,
    input wire clk,
    output reg obf_Q,
    output wire Qn
);
    assign Qn = ~obf_Q;

    always @(posedge clk) begin
        if (S && ~R) begin
            obf_Q <= 1;
        end else if (~S && R) begin
            obf_Q <= 0;
        end else if (~S && ~R) begin
            // Hold previous state
            obf_Q <= obf_Q; 
        end else begin
            // Invalid state
            obf_Q <= 0;
        end
    end
endmodule
